{"code": "import json

# Load all data
children_books = locals()['var_functions.query_db:20']
reviews_file_path = locals()['var_functions.query_db:18']

with open(reviews_file_path, 'r') as f:
    reviews_2020 = json.load(f)

# Create mappings
book_id_to_title = {book['book_id']: book['title'] for book in children_books}

# Filter reviews for children's books only
children_reviews = []
for review in reviews_2020:
    purchase_id = review['purchase_id']
    # Convert purchase_id to book_id format for matching
    book_id = purchase_id.replace('purchaseid_', 'bookid_')
    if book_id in book_id_to_title:
        children_reviews.append({
            'book_id': book_id,
            'title': book_id_to_title[book_id],
            'rating': float(review['rating'])
        })

# Calculate average rating per book
from collections import defaultdict
book_ratings = defaultdict(list)
for review in children_reviews:
    book_ratings[review['title']].append(review['rating'])

# Calculate averages and filter
high_rated_books = []
for title, ratings in book_ratings.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        high_rated_books.append({
            'title': title,
            'average_rating': round(avg_rating, 2),
            'review_count': len(ratings)
        })

# Sort by average rating descending
high_rated_books.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'high_rated_children_books': high_rated_books,
    'total_children_books_reviewed': len(book_ratings),
    'children_reviews_analyzed': len(children_reviews)
}))"}

